def allocate(space):
    for i, node in enumerate(space):
        if not node.get('used'):
            node['used'] = True
            return i
    raise MemoryError('static list is full')

def insert_after(space, pos, value):
    idx = allocate(space)
    space[idx]['value'] = value
    space[idx]['next'] = space[pos]['next']
    space[pos]['next'] = idx
    return idx

