def eval_postfix(tokens):
    stack = []
    for token in tokens:
        if token not in '+-*/':
            stack.append(int(token))
            continue
        b, a = stack.pop(), stack.pop()
        if token == '+': stack.append(a + b)
        elif token == '-': stack.append(a - b)
        elif token == '*': stack.append(a * b)
        else: stack.append(int(a / b))
    return stack[-1]

