def transpose_triplets(rows, cols, triples):
    count = [0] * cols
    for _, j, _ in triples:
        count[j] += 1
    pos = [0] * cols
    for i in range(1, cols):
        pos[i] = pos[i - 1] + count[i - 1]
    result = [None] * len(triples)
    for i, j, v in triples:
        k = pos[j]
        result[k] = (j, i, v)
        pos[j] += 1
    return result

